// Parse webhook body and build Google Sheets API request
const body = $input.first().json.body || $input.first().json;

const spreadsheetId = body.spreadsheetId || '1cgctBCQVmqpfQKdomYLfGAWVwRjT1Qw0-dl9F5RzoOg';
const sheetGid = body.sheetGid !== undefined ? body.sheetGid : 1199154574;
const sheetName = body.sheetName || 'BIA';

// Expect body.rows as array of arrays, or body.row as single array
// Also accept structured patient data
let valueRanges = [];
let mergeRequests = [];

const COLS_PER_OP = 21;
const START_COL = 2; // Column C (0-indexed)

function colToLetter(col) {
  let l = '';
  while (col >= 0) {
    l = String.fromCharCode(65 + (col % 26)) + l;
    col = Math.floor(col / 26) - 1;
  }
  return l;
}

if (body.patients) {
  // Structured patient data mode
  // First, read existing sheet to find next free row
  // For now, use startRow from body or default to 6
  let currentRow = body.startRow || 6;

  body.patients.forEach(patient => {
    const ops = patient.operations || [];
    const maxCols = START_COL + ops.length * COLS_PER_OP;

    // Date row (merged per operation)
    const dateVals = new Array(maxCols).fill('');
    dateVals[0] = String(patient.id || '');
    dateVals[1] = patient.name || '';

    // Data row
    const dataVals = new Array(maxCols).fill('');

    ops.forEach((op, idx) => {
      const co = START_COL + idx * COLS_PER_OP;
      dateVals[co] = op.date ? 'Datum der Operation: ' + op.date : '';

      // Field order: Gewicht, Groesse, BMI, FM_kg, FM_pct, FMI, FFM_kg, FFM_pct, FFMI, SMM, R, Xc, VAT, Taillenumfang, phi, Perzentile, TBW_l, TBW_pct, ECW_l, ECW_pct, ECW_TBW
      const fields = op.fields || op.values || [];
      fields.forEach((v, fi) => {
        if (fi < COLS_PER_OP && v !== null && v !== undefined && v !== '') {
          dataVals[co + fi] = v;
        }
      });

      // Merge date row across operation columns
      mergeRequests.push({
        mergeCells: {
          range: {
            sheetId: sheetGid,
            startRowIndex: currentRow - 1,
            endRowIndex: currentRow,
            startColumnIndex: co,
            endColumnIndex: co + COLS_PER_OP
          },
          mergeType: 'MERGE_ALL'
        }
      });
    });

    const endCol = colToLetter(maxCols - 1);
    valueRanges.push({
      range: sheetName + '!A' + currentRow + ':' + endCol + currentRow,
      values: [dateVals]
    });
    valueRanges.push({
      range: sheetName + '!A' + (currentRow + 1) + ':' + endCol + (currentRow + 1),
      values: [dataVals]
    });

    currentRow += 2;
  });
} else if (body.rows) {
  // Raw rows mode: write rows starting at startRow
  const startRow = body.startRow || 6;
  const startCol = body.startCol || 'A';
  const endCol = body.endCol || 'BM';
  valueRanges.push({
    range: sheetName + '!' + startCol + startRow + ':' + endCol + (startRow + body.rows.length - 1),
    values: body.rows
  });
} else if (body.row) {
  // Single row mode
  const startRow = body.startRow || 6;
  valueRanges.push({
    range: sheetName + '!A' + startRow + ':' + colToLetter(body.row.length - 1) + startRow,
    values: [body.row]
  });
}

return {
  spreadsheetId,
  sheetGid,
  sheetName,
  valueRanges,
  mergeRequests,
  hasFormatting: mergeRequests.length > 0
};
